import {{ Injectable }} from '@nestjs/common';
import {{ CartService }} from './models/cart.model';
import {{ CartServiceRepository }} from './repositories/cart.repository';

@Injectable()
export class CartServiceService {{
  constructor(
    private readonly repository: CartServiceRepository,
  ) {{}}

  async findAll(): Promise<CartService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<CartService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<CartService>): Promise<CartService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<CartService>): Promise<CartService> {{
    return this.repository.update(id, data);
  }}
}}
